import { Link } from 'react-router-dom';

function VideoCard({ video }) {
  return (
    <div className="video-card h-100">
      <img
        className="video-thumb"
        src={video.thumbnailUrl || 'https://placehold.co/600x340?text=Video+Thumbnail'}
        alt={video.title}
      />
      <div className="p-3">
        <h6 className="mb-1 text-truncate">{video.title}</h6>
        <small className="text-muted d-block mb-2">{video.category || 'General'}</small>
        <small className="text-muted d-block mb-3">{video.views || 0} views</small>
        <Link className="btn btn-sm btn-primary" to={`/watch/${video._id}`}>
          Watch
        </Link>
      </div>
    </div>
  );
}

export default VideoCard;
